/**
 * @summary Get a specific scan with results
 */
export const getGetScanUrl = (scanId: string) => {
  return `/api/scans/${scanId}`;
};

export const getScan = async (
  scanId: string,
  options?: RequestInit,
): Promise<Scan> => {
  return customFetch<Scan>(getGetScanUrl(scanId), {
    ...options,
    method: "GET",
  });
};

export const getGetScanQueryKey = (scanId: string) => {
  return [`/api/scans/${scanId}`] as const;
};

export const getGetScanQueryOptions = <
  TData = Awaited<ReturnType<typeof getScan>>,
  TError = ErrorType<ErrorEnvelope>,
>(
  scanId: string,
  options?: {
    query?: UseQueryOptions<Awaited<ReturnType<typeof getScan>>, TError, TData>;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetScanQueryKey(scanId);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getScan>>> = ({
    signal,
  }) => getScan(scanId, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!scanId,
    ...queryOptions,
  } as UseQueryOptions<Awaited<ReturnType<typeof getScan>>, TError, TData> & {
    queryKey: QueryKey;
  };
};

export type GetScanQueryResult = NonNullable<
  Awaited<ReturnType<typeof getScan>>
>;
export type GetScanQueryError = ErrorType<ErrorEnvelope>;

/**
 * @summary Get a specific scan with results
 */

export function useGetScan<
  TData = Awaited<ReturnType<typeof getScan>>,
  TError = ErrorType<ErrorEnvelope>,
>(
  scanId: string,
  options?: {
    query?: UseQueryOptions<Awaited<ReturnType<typeof getScan>>, TError, TData>;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetScanQueryOptions(scanId, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

/**
 * @summary Send scan report by email
 */
export const getSendScanReportUrl = (scanId: string) => {
  return `/api/scans/${scanId}/send-email`;
};

export const sendScanReport = async (
  scanId: string,
  sendReportEmailRequest: SendReportEmailRequest,
  options?: RequestInit,
): Promise<SendReportEmailResponse> => {
  return customFetch<SendReportEmailResponse>(getSendScanReportUrl(scanId), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(sendReportEmailRequest),
  });
};

